function ProfileForm() {
  const [name, setName]         = useState('');
  const [email, setEmail]       = useState('');
  const [age, setAge]           = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError]       = useState(null);

  async function handleSubmit(e) {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    try {
      await saveProfile({ name, email, age });
    } catch (err) {
      setError(err.message);
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <form onSubmit={handleSubmit}>
      <input value={name}  onChange={e => setName(e.target.value)}  placeholder="Name" />
      <input value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" />
      <input value={age}   onChange={e => setAge(Number(e.target.value))} type="number" />
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <button disabled={isSubmitting}>{isSubmitting ? 'Saving…' : 'Save'}</button>
    </form>
  );
}

function Toggle() {
  const [isOpen, setIsOpen]     = useState(false);
  const [count, setCount]       = useState(0);
  const [message, setMessage]   = useState('');

  // Only isOpen re-renders when toggled — count and message are unaffected
  const toggle = () => setIsOpen(o => !o);

  // Only count changes — isOpen and message are unaffected
  const increment = () => setCount(c => c + 1);

  return (
    <div>
      <button onClick={toggle}>{isOpen ? 'Close' : 'Open'}</button>
      <button onClick={increment}>Count: {count}</button>
      <input value={message} onChange={e => setMessage(e.target.value)} />
    </div>
  );
}

