function Cart() {
  const [items, setItems] = useState([]);

  // Do NOT store these — derive during render
  const totalItems = items.length;
  const totalPrice = items.reduce((sum, i) => sum + i.price * i.qty, 0);
  const hasItems   = items.length > 0;
  const isEmpty    = items.length === 0;

  return (
    <div>
      <p>{totalItems} items — ${totalPrice.toFixed(2)}</p>
      {isEmpty && <p>Your cart is empty.</p>}
    </div>
  );
}

function SearchPage() {
  // Independent state — each changes on its own event
  const [query, setQuery]     = useState('');
  const [category, setCategory] = useState('all');
  const [page, setPage]       = useState(1);

  // Status — one variable prevents contradictions
  const [status, setStatus]   = useState('idle'); // 'idle' | 'loading' | 'error'

  // Results — set together with status
  const [results, setResults] = useState([]);
  const [total, setTotal]     = useState(0);

  // Derived — no state needed
  const totalPages = Math.ceil(total / 10);
  const hasResults = results.length > 0;

  useEffect(() => {
    if (!query) return;
    setStatus('loading');
    search({ query, category, page })
      .then(data => {
        setResults(data.items);
        setTotal(data.total);
        setStatus('idle');
      })
      .catch(() => setStatus('error'));
  }, [query, category, page]);

  // Reset page when query or category changes
  function handleQueryChange(e) {
    setQuery(e.target.value);
    setPage(1);
  }

  return (
    <div>
      <input value={query} onChange={handleQueryChange} />
      <select value={category} onChange={e => setCategory(e.target.value)}>
        <option value="all">All</option>
        <option value="docs">Docs</option>
      </select>
      {status === 'loading' && <p>Loading…</p>}
      {status === 'error'   && <p>Error — try again.</p>}
      {hasResults && <ul>{results.map(r => <li key={r.id}>{r.title}</li>)}</ul>}
      <p>Page {page} / {totalPages}</p>
      <button disabled={page <= 1} onClick={() => setPage(p => p - 1)}>Prev</button>
      <button disabled={page >= totalPages} onClick={() => setPage(p => p + 1)}>Next</button>
    </div>
  );
}

