function UserDashboard({ userId }) {
  const [profile, setProfile]     = useState(null);
  const [posts, setPosts]         = useState([]);
  const [followers, setFollowers] = useState(0);

  // Reset everything when userId changes
  useEffect(() => {
    setProfile(null);
    setPosts([]);
    setFollowers(0);
    // Fetch new user data…
    loadUser(userId).then(data => {
      setProfile(data.profile);
      setPosts(data.posts);
      setFollowers(data.followers);
    });
  }, [userId]); // All three setters called in one effect — batched into one re-render

  if (!profile) return <p>Loading…</p>;
  return <div>{profile.name} — {followers} followers</div>;
}

// Custom hook extracts six related state variables
function useSearchFilters() {
  const [query, setQuery]         = useState('');
  const [category, setCategory]   = useState('all');
  const [page, setPage]           = useState(1);
  const [sortKey, setSortKey]     = useState('relevance');
  const [sortDir, setSortDir]     = useState('desc');
  const [dateRange, setDateRange] = useState(null);

  const reset = () => {
    setQuery(''); setCategory('all'); setPage(1);
    setSortKey('relevance'); setSortDir('desc'); setDateRange(null);
  };

  return { query, setQuery, category, setCategory, page, setPage,
           sortKey, setSortKey, sortDir, setSortDir, dateRange, setDateRange, reset };
}

