import { render, screen, fireEvent } from '@testing-library/react';
import ProfileForm from './ProfileForm';

test('name and bio update independently', () => {
  render(<ProfileForm />);

  const nameInput = screen.getByLabelText('Name');
  const bioInput  = screen.getByLabelText('Bio');

  fireEvent.change(nameInput, { target: { value: 'Alice' } });
  fireEvent.change(bioInput,  { target: { value: 'Engineer' } });

  // Each input reflects its own state independently
  expect(nameInput).toHaveValue('Alice');
  expect(bioInput).toHaveValue('Engineer');
});

test('toggling notifications does not affect other fields', () => {
  render(<ProfileForm />);

  const nameInput = screen.getByLabelText('Name');
  const notifToggle = screen.getByRole('checkbox', { name: /notifications/i });

  fireEvent.change(nameInput, { target: { value: 'Bob' } });
  fireEvent.click(notifToggle);

  // Notifications state change left name intact
  expect(nameInput).toHaveValue('Bob');
  expect(notifToggle).toBeChecked();
});

import { renderHook, act } from '@testing-library/react';
import { useSearchFilters } from './useSearchFilters';

test('reset restores all filters to defaults', () => {
  const { result } = renderHook(() => useSearchFilters());

  act(() => {
    result.current.setQuery('react hooks');
    result.current.setCategory('tutorials');
    result.current.setPage(3);
  });

  expect(result.current.query).toBe('react hooks');

  act(() => result.current.reset());

  expect(result.current.query).toBe('');
  expect(result.current.category).toBe('all');
  expect(result.current.page).toBe(1);
});

